(function(w){"use strict";const ID="combination";function p(v){const s=String(v??"").trim();if(!/^\d+$/.test(s))return null;const n=Number(s);return Number.isSafeInteger(n)?n:null}function compute(x){const n=p(x.n),r0=p(x.r);if(n===null||r0===null)return{error:"n과 r에 0 이상의 정수를 입력해 주세요."};if(n>1000)return{error:"n은 1000 이하로 입력해 주세요."};if(r0>n)return{error:"r은 n보다 클 수 없습니다."};const r=Math.min(r0,n-r0);let out=1n;for(let i=1;i<=r;i++)out=out*BigInt(n-r+i)/BigInt(i);const value=out.toString();return{value,digits:value.length}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><p class="hm-calc-hint">서로 다른 n개에서 순서를 고려하지 않고 r개를 뽑는 경우의 수 nCr을 계산합니다.</p><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-comb-n">n</label><input id="hm-comb-n" class="hm-calc-input" inputmode="numeric" placeholder="예: 10"></div><div class="hm-calc-field"><label for="hm-comb-r">r</label><input id="hm-comb-r" class="hm-calc-input" inputmode="numeric" placeholder="예: 3"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">조합 계산</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [n,r]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const out=compute({n:n.value,r:r.value});if(out.error){api.setMessage(msg,out.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("nCr",`<span style="font-size:clamp(16px,2.5vw,28px);word-break:break-all">${out.value}</span>`,`<dl><dt>자릿수</dt><dd>${out.digits}자리</dd></dl>`));});reset.addEventListener("click",()=>{n.value=r.value="";api.setMessage(msg,"");api.clearResult(res);n.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
